roleView.map:
function (doc)
{
  // a proxy for being a role:
  if (doc.context)
  {
    doc.allTypes.forEach(
      function(typeId)
      {
        emit(typeId, doc.id);
      }
    );
  }


}

roleFromContext.map:
function (doc)
 {
  function takeGuid(s)
  {
    return s.substring( s.lastIndexOf("#") + 1 );
  }
  // a proxy for being a role:
  if (doc.context)
  {
    doc.allTypes.forEach(
      function(typeId)
      {
        emit([typeId, takeGuid( doc.context )], doc.id);
      }
    );
  }
 }

credentialsView.map:
function (doc)
 {
    // Only PerspectRol instances have an isMe field. roleAliases
    if (doc.isMe && doc.allTypes.find( t => t == "model://perspectives.domains#tiodn6tcyc$pl2u8t8nih"))
    {
      emit(doc.id, doc.id);
    }
 }

