filled2fillerView.map:
function(filler)
{
  // Every role in the database will appear as 'filler'. Together they form a table.
  // This view outputs another table [filled; {filler, filledContextType, filledRoleType}].
  // We use that table by filtering it with a particular filled role (see getViewOnDatabase).
  // The end result is the row that represents the role that fills the filled role. 
  // The resulting information gives us the filler and the context type and role type of the filled role.
  // The latter two were originally used to register the reverse link from filler to filled.
  // As this view is used in situations where filled role is no longer present, that type information is useful.
  // a proxy for being a role:
  if (filler.context)
  {
    Object.keys( filler.filledRoles ).forEach(
      function( contextType )
      {
        const contextGroup = filler.filledRoles[contextType];
        Object.keys( contextGroup ).forEach(
          function( roleType )
          {
            contextGroup[roleType].forEach(
              function(filledRole)
              {
                emit(filledRole, {filler: filler.id, filledContextType: contextType, filledRoleType: roleType});
              });
          });
      }
    );
  }
}

context2RoleView.map:
function(role)
{
  // a proxy for being a role:
  if (role.context)
  {
    emit( role.context, role.id);
  }
}

role2ContextView.map:
function(context)
{
  // a proxy for being a context.
  if (context.rolInContext)
  {
    Object.values( context.rolInContext ).forEach(
      function(roles)
      {
        roles.forEach( function(role)
        {
          emit(role, context.id);
        });
      }
    );
  }
}

filterValueView.map:
function (doc)
{
  function takeGuid(s)
  {
    return s.substring( s.lastIndexOf("#") + 1 );
  }
  // a proxy for being a role:
  if (doc.context && doc.properties)
  {
    // The FilterValue property URI is the stable generated identifier for
    // model://perspectives.domains#tiodn6tcyc$a2g0s6fcxr$b1h7t3mdwp (filterValueProperty).
    // It is hardcoded here because PouchDB map functions must be self-contained
    // strings with no external dependencies.
    var filterValues = doc.properties["model://perspectives.domains#tiodn6tcyc$x96ouy1wig$iakqeqsarz"];
    if (filterValues && filterValues.length > 0)
    {
      doc.allTypes.forEach(
        function(roleType)
        {
          emit([roleType, takeGuid(doc.context)], { filterValue: filterValues[0], roleId: doc.id });
        }
      );
    }
  }
}
